/* 카드 PIN 여부 업데이트 library.updateCardPin */
UPDATE TB_KNOW_CARD
SET PIN_YN = #{pinYn}
    , MODIFY_DT = NOW()
WHERE CARD_ID = #{cardId}

/* 카드 수정 library.updateCard (기존 카드만 UPDATE, 신규 등록 없음) */
UPDATE TB_KNOW_CARD
SET CATEGORY_ID = #{categoryId}
    , LOG_ID = #{logId}
    , SVC_TY = #{svcTy}
    , TITLE = #{title}
    , TAGS = #{tags}
    , PIN_YN = #{pinYn}
    , ARCHIVE_YN = #{archiveYn}


            , ARCHIVE_DT = NOW()


            , ARCHIVE_DT = NULL


    , SORT_ORD = #{sortOrd, jdbcType=INTEGER}
    , NEW_YN = #{newYn}
    , USE_YN = #{useYn}
    , MODIFY_DT = NOW()
WHERE CARD_ID = #{cardId}
  AND USER_ID = #{userId}

