/* 카테고리 순서 일괄 수정 library.updateCategoryOrder */
UPDATE TB_KNOW_CAT
SET SORT_ORD = CASE CATEGORY_ID

    WHEN #{item.categoryId} THEN #{item.sortOrd}

END
WHERE USER_ID = #{userId}
AND CATEGORY_ID IN

    #{item.categoryId}

/* 카드 이동 library.moveCard */
UPDATE TB_KNOW_CARD
SET CATEGORY_ID = #{targetCategoryId}
    , SORT_ORD = (
        SELECT maxOrd + 1 FROM (
            SELECT IFNULL(MAX(T.SORT_ORD), 0) AS maxOrd
            FROM TB_KNOW_CARD T
            WHERE T.CATEGORY_ID = #{targetCategoryId}
              AND T.USER_ID = #{userId}
        ) AS tmp
    )
    , MODIFY_DT = NOW()
WHERE CARD_ID = #{cardId}
  AND USER_ID = #{userId}

/* 카드 순서·카테고리 일괄 수정 library.updateCardOrder (카테고리 간 이동 포함) */
UPDATE TB_KNOW_CARD
SET CATEGORY_ID = CASE CARD_ID


        WHEN #{card.cardId} THEN #{cat.categoryId}


END
, SORT_ORD = CASE CARD_ID


        WHEN #{card.cardId} THEN #{card.sortOrd, jdbcType=INTEGER}


END
, MODIFY_DT = NOW()
WHERE USER_ID = #{userId}
AND CARD_ID IN


        #{card.cardId}

