/* 지식카드 차트 저장 library.insertKnowChart */
INSERT INTO TB_KNOW_CARD_CHART (
    CHART_ID
    , CARD_ID
    , CHART_TYPE
    , CHART_TARGET_KEY
    , Y_AXIS_KEYS
    , SERIES_KEY
    , STAT_ID_FILTER
    , STACK_YN
    , DUAL_AXIS_YN
    , YL_CHART_TYPE
    , YR_CHART_TYPE
    , SORT_ORD
    , CREATE_USER_ID
    , CREATE_DT
) VALUES (
    #{chartId}
    , #{cardId}
    , #{chartType}
    , #{chartTargetKey}
    , #{yAxisKeysJson}
    , #{seriesKey}
    , #{statIdFilter}
    , #{stackYn}
    , #{dualAxisYn}
    , #{ylChartType, jdbcType=VARCHAR}
    , #{yrChartType, jdbcType=VARCHAR}
    , #{sortOrd, jdbcType=INTEGER}
    , #{createUserId}
    , NOW()
)

mapper.delete:
/* 지식카드 차트 삭제 library.deleteKnowChart */
DELETE C
FROM TB_KNOW_CARD_CHART C
INNER JOIN TB_KNOW_CARD K
    ON C.CARD_ID = K.CARD_ID
WHERE C.CHART_ID = #{chartId}
    AND K.USER_ID = #{userId}

mapper.update:
/* 지식카드 차트 수정 library.updateKnowChart */
UPDATE TB_KNOW_CARD_CHART C
INNER JOIN TB_KNOW_CARD K
    ON C.CARD_ID = K.CARD_ID
SET C.CHART_TYPE = #{chartType}
    , C.CHART_TARGET_KEY = #{chartTargetKey}
    , C.Y_AXIS_KEYS = #{yAxisKeysJson}
    , C.SERIES_KEY = #{seriesKey}
    , C.STAT_ID_FILTER = #{statIdFilter}
    , C.STACK_YN = #{stackYn}
    , C.DUAL_AXIS_YN = #{dualAxisYn}
    , C.YL_CHART_TYPE = #{ylChartType, jdbcType=VARCHAR}
    , C.YR_CHART_TYPE = #{yrChartType, jdbcType=VARCHAR}
    , C.SORT_ORD = #{sortOrd, jdbcType=INTEGER}
    , C.MODIFY_DT = NOW()
WHERE C.CHART_ID = #{chartId}
    AND K.USER_ID = #{userId}

